+  }
+
+  /** Next named sibling. */
+  next(): SgNode | null {
+    wasm.node_next(this._srcHandle, this._info.sb, this._info.eb, this._ir());
+    return this._makeNode(readNodeResult());
+  }
+
+  /** Previous named sibling. */
+  prev(): SgNode | null {
