+        w.writeByte(']') catch return 0;
+
+        // Fix template
+        if (rule.fix_len > 0) {
+            w.writeAll(",\"fix\":\"") catch return 0;
+            writeJsonEscaped(w, rs.bytecode[rule.fix_offset..][0..rule.fix_len]) catch return 0;
+            w.writeByte('"') catch return 0;
+        }
