+
+fn writeJsonEscaped(w: anytype, s: []const u8) !void {
+    for (s) |c_byte| {
+        switch (c_byte) {
+            '"' => try w.writeAll("\\\""),
+            '\\' => try w.writeAll("\\\\"),
+            '\n' => try w.writeAll("\\n"),
+            '\r' => try w.writeAll("\\r"),
+            '\t' => try w.writeAll("\\t"),
+            else => {
+                if (c_byte < 0x20) {
+                    try w.writeAll("\\u00");
+                    try w.print("{x:0>2}", .{c_byte});
+                } else {
+                    try w.writeByte(c_byte);
+                }
+            },
+        }
+    }
+}
