+
+    /* Validate the block */
+    if (block->magic != BLOCK_MAGIC) {
+        /* Invalid free -- corrupted or double-free. Silently ignore in
+         * WASM context (no stderr to report to). */
+        return;
+    }
+
+    /* Forward coalescing: merge with next adjacent block if free.
+     * Critical for tree-sitter which allocates many small blocks per parse. */
+    unsigned char *next_addr = (unsigned char *)block + HEADER_SIZE + block->size;
+    if (next_addr < heap_ptr) {
+        struct block_header *next = (struct block_header *)next_addr;
+        if (next->magic == FREE_MAGIC) {
+            remove_from_free_list(next);
+            block->size += HEADER_SIZE + next->size;
+            next->magic = 0;
+        }
+    }
+
+    insert_into_free_list(block);
+}
+
+void *calloc(size_t nmemb, size_t size) {
+    /* Check for overflow */
+    if (nmemb != 0 && size > (size_t)-1 / nmemb) {
+        return NULL;
+    }
+
+    size_t total = nmemb * size;
+    void *ptr = malloc(total);
+    if (ptr == NULL) {
+        return NULL;
+    }
+
+    /* Zero the memory */
+    unsigned char *p = (unsigned char *)ptr;
+    for (size_t i = 0; i < total; i++) {
+        p[i] = 0;
+    }
+
+    return ptr;
+}
+
+void *realloc(void *ptr, size_t size) {
+    if (ptr == NULL) {
+        return malloc(size);
+    }
+
+    if (size == 0) {
+        free(ptr);
+        return NULL;
+    }
+
+    struct block_header *block =
+        (struct block_header *)((unsigned char *)ptr - HEADER_SIZE);
+
+    if (block->magic != BLOCK_MAGIC) {
+        return NULL;
+    }
+
+    /* If the existing block is big enough, keep it */
+    size_t aligned_size = align_up(size, ALIGNMENT);
+    if (block->size >= aligned_size) {
+        /* Optionally split if much larger */
+        maybe_split(block, aligned_size);
+        return ptr;
+    }
+
+    /* Allocate new block, copy, free old */
+    void *new_ptr = malloc(size);
+    if (new_ptr == NULL) {
+        return NULL;
+    }
+
+    /* Copy old data */
+    unsigned char *src = (unsigned char *)ptr;
+    unsigned char *dst = (unsigned char *)new_ptr;
+    size_t copy_size = block->size < size ? block->size : size;
+    for (size_t i = 0; i < copy_size; i++) {
+        dst[i] = src[i];
+    }
+
+    free(ptr);
+    return new_ptr;
+}
+
+/* ── Required C runtime stubs ───────────────────────────── */
+
+/*
+ * abort() -- required by some C code paths.
+ * In WASM freestanding we trap via unreachable.
+ */
+_Noreturn void abort(void) {
+    __builtin_trap();
+}
+
+/*
+ * memset -- needed by calloc and general C code.
+ * Provided here in case the compiler doesn't inline it.
+ */
+void *memset(void *s, int c, size_t n) {
+    unsigned char *p = (unsigned char *)s;
+    for (size_t i = 0; i < n; i++) {
+        p[i] = (unsigned char)c;
+    }
+    return s;
+}
+
+/*
+ * memcpy -- byte-by-byte copy.
+ */
+void *memcpy(void *dest, const void *src, size_t n) {
+    unsigned char *d = (unsigned char *)dest;
+    const unsigned char *s = (const unsigned char *)src;
+    for (size_t i = 0; i < n; i++) {
+        d[i] = s[i];
+    }
+    return dest;
+}
+
+/*
+ * memmove -- safe overlapping copy.
+ */
+void *memmove(void *dest, const void *src, size_t n) {
+    unsigned char *d = (unsigned char *)dest;
+    const unsigned char *s = (const unsigned char *)src;
+    if (d < s) {
+        for (size_t i = 0; i < n; i++) {
+            d[i] = s[i];
+        }
+    } else if (d > s) {
+        for (size_t i = n; i > 0; i--) {
+            d[i - 1] = s[i - 1];
+        }
+    }
+    return dest;
+}
+
+/*
+ * memcmp -- byte comparison.
+ */
+int memcmp(const void *s1, const void *s2, size_t n) {
+    const unsigned char *a = (const unsigned char *)s1;
+    const unsigned char *b = (const unsigned char *)s2;
+    for (size_t i = 0; i < n; i++) {
+        if (a[i] != b[i]) {
+            return (int)a[i] - (int)b[i];
+        }
+    }
+    return 0;
+}
+
+/*
+ * strlen -- string length.
+ */
+size_t strlen(const char *s) {
+    size_t len = 0;
+    while (s[len] != '\0') {
+        len++;
+    }
+    return len;
+}
+
+/*
+ * strncpy -- bounded string copy.
+ */
+char *strncpy(char *dest, const char *src, size_t n) {
+    size_t i;
+    for (i = 0; i < n && src[i] != '\0'; i++) {
+        dest[i] = src[i];
+    }
+    for (; i < n; i++) {
+        dest[i] = '\0';
+    }
+    return dest;
+}
+
+/*
+ * strncmp -- bounded string comparison.
+ */
+int strncmp(const char *s1, const char *s2, size_t n) {
+    for (size_t i = 0; i < n; i++) {
+        if (s1[i] != s2[i]) {
+            return (unsigned char)s1[i] - (unsigned char)s2[i];
+        }
+        if (s1[i] == '\0') {
+            return 0;
+        }
+    }
+    return 0;
+}
+
+/*
+ * strcmp -- string comparison.
+ */
+int strcmp(const char *s1, const char *s2) {
+    while (*s1 && (*s1 == *s2)) {
+        s1++;
+        s2++;
+    }
+    return (unsigned char)*s1 - (unsigned char)*s2;
+}
+
+/*
+ * strchr -- find character in string.
+ */
+char *strchr(const char *s, int c) {
+    while (*s != '\0') {
+        if (*s == (char)c) {
+            return (char *)s;
+        }
+        s++;
+    }
+    if (c == '\0') {
+        return (char *)s;
+    }
+    return NULL;
+}
+
+/*
+ * atoi -- string to integer.
+ */
+int atoi(const char *nptr) {
+    int result = 0;
+    int sign = 1;
+
+    /* Skip whitespace */
+    while (*nptr == ' ' || *nptr == '\t' || *nptr == '\n' ||
+           *nptr == '\r' || *nptr == '\f' || *nptr == '\v') {
+        nptr++;
+    }
+
+    if (*nptr == '-') {
+        sign = -1;
+        nptr++;
+    } else if (*nptr == '+') {
+        nptr++;
+    }
+
+    while (*nptr >= '0' && *nptr <= '9') {
+        result = result * 10 + (*nptr - '0');
+        nptr++;
+    }
+
+    return sign * result;
+}
+
+/*
+ * strtol -- string to long with base.
+ */
+long strtol(const char *nptr, char **endptr, int base) {
+    long result = 0;
+    int sign = 1;
+
+    /* Skip whitespace */
+    while (*nptr == ' ' || *nptr == '\t' || *nptr == '\n' ||
+           *nptr == '\r' || *nptr == '\f' || *nptr == '\v') {
+        nptr++;
+    }
+
+    if (*nptr == '-') {
+        sign = -1;
+        nptr++;
+    } else if (*nptr == '+') {
+        nptr++;
+    }
+
+    /* Auto-detect base */
+    if (base == 0) {
+        if (*nptr == '0') {
+            nptr++;
+            if (*nptr == 'x' || *nptr == 'X') {
+                base = 16;
+                nptr++;
+            } else {
+                base = 8;
+            }
+        } else {
+            base = 10;
+        }
+    } else if (base == 16) {
+        if (nptr[0] == '0' && (nptr[1] == 'x' || nptr[1] == 'X')) {
+            nptr += 2;
+        }
+    }
+
+    while (1) {
+        int digit;
+        if (*nptr >= '0' && *nptr <= '9') {
+            digit = *nptr - '0';
+        } else if (*nptr >= 'a' && *nptr <= 'z') {
+            digit = *nptr - 'a' + 10;
+        } else if (*nptr >= 'A' && *nptr <= 'Z') {
+            digit = *nptr - 'A' + 10;
+        } else {
+            break;
+        }
+        if (digit >= base) {
+            break;
+        }
+        result = result * base + digit;
+        nptr++;
+    }
+
+    if (endptr != NULL) {
+        *endptr = (char *)nptr;
+    }
+
+    return sign * result;
+}

