+                '*' => {
+                    self.advance();
+                    const ptr = try self.allocator.create(Expr);
+                    ptr.* = atom;
+                    return Expr{ .star = ptr };
+                },
+                '+' => {
+                    self.advance();
+                    const ptr = try self.allocator.create(Expr);
+                    ptr.* = atom;
+                    return Expr{ .plus = ptr };
+                },
+                '?' => {
+                    self.advance();
+                    const ptr = try self.allocator.create(Expr);
+                    ptr.* = atom;
+                    return Expr{ .question = ptr };
+                },
+                '{' => {
+                    return try self.parseRepeat(atom);
+                },
+                else => {},
+            }
+        }
