+        const min = try self.parseNumber();
+
+        var max: ?usize = null;
+
+        if (self.peek()) |c| {
+            if (c == ',') {
+                self.advance(); // consume ','
+
+                // Check if there's a max
+                if (self.peek()) |next| {
