+                    }
+                    // else: unbounded {n,}
+                }
+            } else {
+                // Exact count {n}
+                max = min;
+            }
+        }
+
+        if (self.peek() != '}') {
+            return error.InvalidRepeat;
+        }
+        self.advance(); // consume '}'
+
+        const ptr = try self.allocator.create(Expr);
+        ptr.* = atom;
+
+        return Expr{ .repeat = .{
+            .expr = ptr,
+            .min = min,
+            .max = max,
+        } };
+    }
+
+    fn parseNumber(self: *Parser) ParseError!usize {
+        var num: usize = 0;
+        var found = false;
+
+        while (self.peek()) |c| {
+            if (c < '0' or c > '9') break;
+            found = true;
+            num = num * 10 + (c - '0');
+            self.advance();
+        }
+
+        if (!found) return error.InvalidRepeat;
+        return num;
+    }
+
+    fn parseAtom(self: *Parser) ParseError!Expr {
+        const c = self.peek() orelse return error.UnexpectedEOF;
+
+        switch (c) {
+            '.' => {
+                self.advance();
+                return Expr{ .any = {} };
+            },
+            '^' => {
+                self.advance();
+                return Expr{ .start = {} };
+            },
+            '$' => {
+                self.advance();
+                return Expr{ .end = {} };
+            },
+            '(' => {
+                return try self.parseGroup();
+            },
+            '[' => {
+                return try self.parseCharClass();
+            },
+            '\\' => {
+                return try self.parseEscape();
+            },
+            // Metacharacters that shouldn't appear as atoms - invalid regex syntax
+            '*', '+', '?', '{', '}', '|', ')' => {
+                return error.InvalidMetacharacter;
+            },
+            else => {
+                self.advance();
+                return Expr{ .char = c };
+            },
+        }
+    }
