+    fn parseGroup(self: *Parser) ParseError!Expr {
+        self.advance(); // consume '('
+
+        const inner = try self.parseAlt();
+
+        if (self.peek() != ')') {
+            return error.UnbalancedParens;
+        }
+        self.advance(); // consume ')'
