+
+                    const end = if (self.peek() == '\\') blk: {
+                        self.advance();
+                        break :blk try self.parseEscapeChar();
+                    } else blk: {
+                        const e = self.peek() orelse return error.InvalidCharClass;
+                        self.advance();
+                        break :blk e;
+                    };
