+        if (self.peek() != ']') {
+            return error.InvalidCharClass;
+        }
+        self.advance(); // consume ']'
+
+        return Expr{ .class = .{
+            .negated = negated,
+            .ranges = try ranges.toOwnedSlice(self.allocator),
+        } };
+    }
